+    const config = getPackageManagerCommands("uv");
+    expect(config.run).toBe("uv run");
+    expect(config.exec).toBe("uvx");
+    expect(config.install).toBe("uv pip install");
+    expect(config.installSilent).toBe("uv pip install -q");
+  });
 });

